    let mut min_time = i64::MAX;

    for &land_start in landStartTime.iter() {
        for &water_start in waterStartTime.iter() {
            let land_end = land_start + landDuration[landStartTime.iter().position(|&x| x == land_start).unwrap()];
            let water_end = water_start + waterDuration[waterStartTime.iter().position(|&x| x == water_start).unwrap()];

