            let total2 = start_land + landDuration[landStartTime.iter().position(|&x| x == land_start).unwrap()];

            let current_min = std::cmp::min(total1, total2);
            if current_min < min_time {
                min_time = current_min;
            }
        }
    }

    min_time
}
