fn solve(land_start_time: Vec<i64>, land_duration: Vec<i64>, water_start_time: Vec<i64>, water_duration: Vec<i64>) -> i64 {
    let mut min_time = i64::MAX;

    for i in 0..land_start_time.len() {
        for j in 0..water_start_time.len() {
            let land_end = land_start_time[i] + land_duration[i];
            let time_after_water = water_start_time[j].max(land_end) + water_duration[j];

            let water_end = water_start_time[j] + water_duration[j];
            let time_after_land = land_start_time[i].max(water_end) + land_duration[i];

            min_time = min_time.min(time_after_water.min(time_after_land));
        }
    }

    min_time
}
